#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005

int A[MAXN];
int X, Y;
int N;
int adj[MAXN][MAXN];

void dfs(int u, int v, int *sum, int *count, int *visited) {
    visited[u] = 1;
    *sum += A[u];
    (*count)++;
    if (u == v) return;
    for (int i = 1; i <= N; i++) {
        if (adj[u][i] && !visited[i]) {
            dfs(i, v, sum, count, visited);
        }
    }
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &X, &Y);
        for (int i = 1; i <= N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                adj[i][j] = 0;
            }
        }
        for (int i = 1; i < N; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            adj[u][v] = adj[v][u] = 1;
        }
        int count = 0;
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                int sum = 0;
                int visited[MAXN];
                for (int k = 1; k <= N; k++) {
                    visited[k] = 0;
                }
                int cnt = 0;
                dfs(i, j, &sum, &cnt, visited);
                double mean = (double)sum / cnt;
                int median;
                if (cnt % 2 == 0) {
                    median = (A[i] + A[j]) / 2;
                } else {
                    median = A[i];
                }
                if (median <= X && mean >= Y) {
                    count++;
                }
            }
        }
        printf("%d\n", count);
    }
    return 0;
}

